import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Slot } from "radix-ui"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button inline-flex shrink-0 items-center justify-center rounded-lg border border-transparent bg-clip-padding text-sm font-medium whitespace-nowrap transition-all outline-none select-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground [a]:hover:bg-primary/80",
        outline:
          "border-border bg-background hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80 aria-expanded:bg-secondary aria-expanded:text-secondary-foreground",
        ghost:
          "hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:hover:bg-muted/50",
        destructive:
          "bg-destructive/10 text-destructive hover:bg-destructive/20 focus-visible:border-destructive/40 focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:hover:bg-destructive/30 dark:focus-visible:ring-destructive/40",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default:
          "h-8 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-2 has-data-[icon=inline-start]:pl-2",
        xs: "h-6 gap-1 rounded-[min(var(--radius-md),10px)] px-2 text-xs in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-7 gap-1 rounded-[min(var(--radius-md),12px)] px-2.5 text-[0.8rem] in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3.5",
        lg: "h-9 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-3 has-data-[icon=inline-start]:pl-3",
        icon: "size-8",
        "icon-xs":
          "size-6 rounded-[min(var(--radius-md),10px)] in-data-[slot=button-group]:rounded-lg [&_svg:not([class*='size-'])]:size-3",
        "icon-sm":
          "size-7 rounded-[min(var(--radius-md),12px)] in-data-[slot=button-group]:rounded-lg",
        "icon-lg": "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import { useState, useEffect } from 'react';
import { api } from '../../services/api';
import { ShieldCheck, CalendarRange, Clock, Edit3, DollarSign } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

interface DoctorProfileData {
  specializations: string[];
  experience: number;
  qualifications: string[];
  bio: string | null;
  consultationFee: number | null;
  availableFrom: string | null;
  availableTo: string | null;
}

const DoctorProfile = () => {
  const [formData, setFormData] = useState<DoctorProfileData>({
    specializations: [],
    experience: 0,
    qualifications: [],
    bio: '',
    consultationFee: 0,
    availableFrom: '',
    availableTo: ''
  });
  
  const [specializationsInput, setSpecializationsInput] = useState('');
  const [qualificationsInput, setQualificationsInput] = useState('');
  
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [message, setMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      setIsLoading(true);
      const res = await api.get('/doctor/profile');
      if (res.data.success && res.data.data.profile) {
        const profile = res.data.data.profile;
        setFormData({
          specializations: profile.specializations || [],
          experience: profile.experience || 0,
          qualifications: profile.qualifications || [],
          bio: profile.bio || '',
          consultationFee: profile.consultationFee || 0,
          availableFrom: profile.availableFrom || '',
          availableTo: profile.availableTo || ''
        });
        setSpecializationsInput((profile.specializations || []).join(', '));
        setQualificationsInput((profile.qualifications || []).join(', '));
      }
    } catch (err: any) {
      console.error('Error fetching profile:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    setMessage(null);

    const payload = {
      ...formData,
      specializations: specializationsInput.split(',').map(s => s.trim()).filter(Boolean),
      qualifications: qualificationsInput.split(',').map(s => s.trim()).filter(Boolean),
      experience: Number(formData.experience),
      consultationFee: formData.consultationFee ? Number(formData.consultationFee) : null,
      availableFrom: formData.availableFrom || null,
      availableTo: formData.availableTo || null,
      bio: formData.bio || null,
    };

    try {
      await api.put('/doctor/profile', payload);
      setMessage({ type: 'success', text: 'Profile updated successfully!' });
      setSpecializationsInput(payload.specializations.join(', '));
      setQualificationsInput(payload.qualifications.join(', '));
    } catch (err: any) {
      const errMsg = err.response?.data?.message || 'Failed to update profile. Please verify your details.';
      setMessage({ type: 'error', text: errMsg });
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex justify-center p-12">
        <div className="animate-spin rounded-full h-10 w-10 border-4 border-primary border-t-transparent"></div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto space-y-8 font-sans px-4 py-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row items-center justify-between bg-white p-8 rounded-3xl shadow-sm border border-zinc-200">
        <div className="flex items-center gap-4">
           <div className="p-4 bg-orange-50 text-primary rounded-2xl">
             <Edit3 className="h-8 w-8" />
           </div>
           <div>
             <h1 className="text-3xl font-extrabold text-zinc-900 tracking-tight">Profile Settings</h1>
             <p className="text-zinc-500 mt-1 font-medium">Manage your professional details, specialties and availability</p>
           </div>
        </div>
      </div>

      {message && (
        <div className={`p-4 rounded-xl shadow-sm border font-semibold flex items-center gap-2 ${message.type === 'success' ? 'bg-green-50 text-green-700 border-green-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
          {message.type === 'success' && <ShieldCheck className="h-5 w-5" />}
          {message.text}
        </div>
      )}

      {/* Form Card */}
      <Card className="rounded-3xl border-zinc-200 shadow-sm overflow-hidden bg-white">
        <CardContent className="p-8">
          <form onSubmit={handleSave} className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              
              <div className="space-y-2">
                <Label className="text-zinc-700 font-bold">Specializations (comma separated)</Label>
                <Input 
                  type="text" 
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl"
                  placeholder="e.g. Cardiologist, General Physician"
                  value={specializationsInput}
                  onChange={e => setSpecializationsInput(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <Label className="text-zinc-700 font-bold">Qualifications (comma separated)</Label>
                <Input 
                  type="text" 
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl"
                  placeholder="e.g. MBBS, MD"
                  value={qualificationsInput}
                  onChange={e => setQualificationsInput(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <Label className="text-zinc-700 font-bold flex items-center gap-2">
                  <CalendarRange className="h-4 w-4 text-primary" /> Years of Experience
                </Label>
                <Input 
                  type="number" 
                  min="0"
                  required
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl"
                  value={formData.experience}
                  onChange={e => setFormData({ ...formData, experience: Number(e.target.value) })}
                />
              </div>

              <div className="space-y-2">
                <Label className="text-zinc-700 font-bold flex items-center gap-2">
                  <DollarSign className="h-4 w-4 text-primary" /> Consultation Fee ($)
                </Label>
                <Input 
                  type="number" 
                  min="0"
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl"
                  value={formData.consultationFee || ''}
                  onChange={e => setFormData({ ...formData, consultationFee: Number(e.target.value) })}
                />
              </div>

              <div className="space-y-2 flex flex-col justify-end">
                <Label className="text-zinc-700 font-bold flex items-center gap-2 mb-2">
                  <Clock className="h-4 w-4 text-primary" /> Availability Time Window
                </Label>
                <div className="flex items-center gap-4">
                  <Input 
                    type="time" 
                    className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl flex-1"
                    value={formData.availableFrom || ''}
                    onChange={e => setFormData({ ...formData, availableFrom: e.target.value })}
                  />
                  <span className="text-zinc-400 font-bold">TO</span>
                  <Input 
                    type="time" 
                    className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl flex-1"
                    value={formData.availableTo || ''}
                    onChange={e => setFormData({ ...formData, availableTo: e.target.value })}
                  />
                </div>
              </div>
              
            </div>

            <div className="space-y-2 pt-4 border-t border-zinc-100">
              <Label className="text-zinc-700 font-bold">Professional Bio</Label>
              <textarea 
                rows={4}
                className="w-full p-4 bg-zinc-50 border border-zinc-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary resize-none text-sm"
                placeholder="Tell your patients about your practice..."
                value={formData.bio || ''}
                onChange={e => setFormData({ ...formData, bio: e.target.value })}
              />
            </div>

            <div className="flex justify-end pt-6">
              <Button 
                type="submit" 
                disabled={isSaving}
                className="px-8 h-12 bg-primary hover:bg-orange-600 text-white font-bold rounded-xl shadow-lg shadow-primary/20 transition-transform active:scale-95 text-base"
              >
                {isSaving ? 'Saving Changes...' : 'Save Profile Details'}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

export default DoctorProfile;

import { useState } from 'react';
import { Link } from 'react-router-dom';
import { api } from '../../services/api';
import { type TimeSlot } from '../../types/appointment';
import { ChevronLeft, CalendarClock, Clock, CheckCircle } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

const ManageSlots = () => {
  const today = new Date().toISOString().split('T')[0];
  const [date, setDate] = useState(today);
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('17:00');
  const [generatedSlots, setGeneratedSlots] = useState<TimeSlot[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage(null);
    setGeneratedSlots([]);

    try {
      const res = await api.post('/doctor/time-slots', { date, startTime, endTime });
      if (res.data.success) {
        const slots: TimeSlot[] = Array.isArray(res.data.data) ? res.data.data : [];
        setGeneratedSlots(slots);
        setMessage({
          type: 'success',
          text: `${slots.length} slot${slots.length !== 1 ? 's' : ''} created for ${date}.`,
        });
      }
    } catch (err: any) {
      setMessage({
        type: 'error',
        text: err.response?.data?.message || 'Failed to create slots. Check your time range.',
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6 font-sans px-4 py-8">
      <Link
        to="/doctor-dashboard"
        className="inline-flex items-center text-sm font-bold text-zinc-500 hover:text-primary transition-colors bg-white hover:bg-orange-50 px-4 py-2 rounded-full border border-zinc-200"
      >
        <ChevronLeft size={16} className="mr-1" /> Back to Dashboard
      </Link>

      <div className="bg-white p-8 rounded-3xl shadow-sm border border-zinc-200 flex items-center gap-4">
        <div className="p-4 bg-orange-50 text-primary rounded-2xl">
          <CalendarClock className="h-8 w-8" />
        </div>
        <div>
          <h1 className="text-2xl font-extrabold text-zinc-900">Manage Availability</h1>
          <p className="text-zinc-500 font-medium mt-1">
            Set a date and time range to auto-generate 30-minute slots.
          </p>
        </div>
      </div>

      {message && (
        <div
          className={`p-4 rounded-xl border font-semibold flex items-center gap-2 ${
            message.type === 'success'
              ? 'bg-green-50 text-green-700 border-green-200'
              : 'bg-red-50 text-red-700 border-red-200'
          }`}
        >
          {message.type === 'success' && <CheckCircle className="h-5 w-5" />}
          {message.text}
        </div>
      )}

      <Card className="rounded-3xl border-zinc-200 shadow-sm">
        <CardContent className="p-8">
          <form onSubmit={handleGenerate} className="space-y-6">
            <div className="space-y-2">
              <Label className="text-zinc-700 font-bold">Date</Label>
              <Input
                type="date"
                min={today}
                required
                value={date}
                onChange={e => setDate(e.target.value)}
                className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl max-w-xs"
              />
            </div>

            <div className="space-y-2">
              <Label className="text-zinc-700 font-bold flex items-center gap-2">
                <Clock size={16} className="text-primary" /> Time Range
              </Label>
              <div className="flex items-center gap-4">
                <Input
                  type="time"
                  required
                  value={startTime}
                  onChange={e => setStartTime(e.target.value)}
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl flex-1 max-w-[160px]"
                />
                <span className="text-zinc-400 font-bold text-sm">TO</span>
                <Input
                  type="time"
                  required
                  value={endTime}
                  onChange={e => setEndTime(e.target.value)}
                  className="h-12 bg-zinc-50 border-zinc-200 focus-visible:ring-primary rounded-xl flex-1 max-w-[160px]"
                />
              </div>
              <p className="text-xs text-zinc-400 font-medium">
                30-minute slots will be generated within this window.
              </p>
            </div>

            <Button
              type="submit"
              disabled={isLoading}
              className="px-8 h-12 bg-primary hover:bg-orange-600 text-white font-bold rounded-xl shadow-lg shadow-primary/20"
            >
              {isLoading ? 'Generating...' : 'Generate Slots'}
            </Button>
          </form>
        </CardContent>
      </Card>

      {generatedSlots.length > 0 && (
        <Card className="rounded-3xl border-zinc-200 shadow-sm">
          <CardContent className="p-8">
            <h2 className="text-lg font-extrabold text-zinc-900 mb-4">
              Generated Slots — {date}
            </h2>
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
              {generatedSlots.map(slot => (
                <div
                  key={slot.id}
                  className="p-3 rounded-xl text-sm font-bold border bg-orange-50 text-primary border-orange-100 text-center"
                >
                  {slot.startTime}
                  <span className="block text-xs text-zinc-400 font-medium">–{slot.endTime}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default ManageSlots;

import { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { api } from '../../services/api';
import { User, Briefcase, Award, Clock, DollarSign, ChevronLeft, CalendarDays } from 'lucide-react';
import { Button } from '@/components/ui/button';

interface FullDoctorProfile {
  user: {
    id: string;
    name: string;
    email: string;
    createdAt: string;
  };
  profile: {
    id: string;
    specializations: string[];
    experience: number;
    qualifications: string[];
    bio: string | null;
    consultationFee: number | null;
    availableFrom: string | null;
    availableTo: string | null;
  } | null;
}

const DoctorDetails = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [data, setData] = useState<FullDoctorProfile | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchDoctorDetails = async () => {
      try {
        const res = await api.get(`/patient/doctors/${id}`);
        if (res.data.success && res.data.data) {
          setData(res.data.data);
        } else {
          setError('Doctor profile not found');
        }
      } catch (err: any) {
        setError(err.response?.data?.message || 'Failed to fetch doctor details');
      } finally {
        setIsLoading(false);
      }
    };

    if (id) fetchDoctorDetails();
  }, [id]);

  if (isLoading) {
    return (
      <div className="flex justify-center p-12">
        <div className="animate-spin rounded-full h-10 w-10 border-4 border-primary border-t-transparent"></div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className="max-w-4xl mx-auto text-center p-12 bg-white rounded-3xl shadow-sm border border-red-100 font-sans">
        <h2 className="text-2xl font-bold text-red-600 mb-2">Profile Not Found</h2>
        <p className="text-zinc-600 mb-6 font-medium">{error || "We couldn't locate this doctor's profile."}</p>
        <Link to="/patient-dashboard/doctors" className="text-primary font-bold hover:underline inline-flex items-center">
          <ChevronLeft size={16} className="mr-1" /> Back to Directory
        </Link>
      </div>
    );
  }

  const { user, profile } = data;

  return (
    <div className="max-w-5xl mx-auto space-y-6 font-sans px-4 py-8">
      <Link to="/patient-dashboard/doctors" className="inline-flex items-center text-sm font-bold text-zinc-500 hover:text-primary transition-colors bg-white hover:bg-orange-50 px-4 py-2 rounded-full border border-zinc-200">
        <ChevronLeft size={16} className="mr-1" /> Back to Doctors
      </Link>

      <div className="bg-white rounded-[2rem] shadow-sm border border-zinc-200 overflow-hidden relative">
        {/* Abstract Header Graphic */}
        <div className="h-40 bg-gradient-to-r from-orange-400 to-primary relative overflow-hidden">
           <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSIyMCIgaGVpZ2h0PSIyMCI+Cgk8cmVjdCB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIGZpbGw9Im5vbmUiLz4KCTxwb2x5Z29uIHBvaW50cz0iMjAsMjAgMCwyMCAwLDAiIGZpbGw9IiNmOWNhMjQiIGZpbGwtb3BhY2l0eT0iMC4wNSIvPgo8L3N2Zz4=')] opacity-30 mix-blend-overlay" />
        </div>

        <div className="px-10 pb-12">
          {/* Avatar & Action row */}
          <div className="relative flex justify-between items-end -mt-16 mb-8">
            <div className="h-32 w-32 rounded-[2rem] bg-white p-2 shadow-xl border border-zinc-100 transform rotate-3">
               <div className="h-full w-full rounded-2xl bg-orange-50 flex items-center justify-center text-primary transform -rotate-3">
                 <User size={64} className="opacity-80" />
               </div>
            </div>

            <div className="flex gap-4 items-center">
              {profile?.consultationFee != null && (
                <div className="bg-white text-zinc-800 border border-zinc-200 px-6 py-3 rounded-xl font-bold flex items-center shadow-lg transform -translate-y-2">
                  <DollarSign size={18} className="mr-1 text-green-600" />
                  <span className="text-xl">{profile.consultationFee}</span> <span className="text-zinc-400 text-sm ml-1 font-medium">/ session</span>
                </div>
              )}
              <Button
                onClick={() => navigate(`/patient-dashboard/doctor/${id}/book`)}
                className="bg-primary hover:bg-orange-600 font-bold rounded-xl px-6 h-12 shadow-lg transform -translate-y-2 flex items-center gap-2"
              >
                <CalendarDays size={18} /> Book Appointment
              </Button>
            </div>
          </div>

          <h1 className="text-4xl font-extrabold text-zinc-900 tracking-tight">Dr. {user.name}</h1>
          <p className="text-zinc-500 mt-2 font-medium">{user.email}</p>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 mt-12 pt-12 border-t border-zinc-100">
            <div className="space-y-10">
              <div>
                <h3 className="text-xs font-bold text-primary tracking-widest uppercase mb-4 flex items-center">
                  <Briefcase size={16} className="mr-2" /> Professional Summary
                </h3>
                <div className="bg-zinc-50 rounded-2xl p-6 border border-zinc-100">
                  <div className="text-3xl font-extrabold text-zinc-900 mb-2">{profile?.experience || 0} <span className="text-lg text-zinc-500 font-bold">Years</span></div>
                  <p className="text-zinc-500 font-medium">Clinical Experience</p>
                  <p className="text-zinc-700 mt-6 leading-relaxed">
                    {profile?.bio || 'This doctor has not provided a biographical summary yet.'}
                  </p>
                </div>
              </div>

              <div>
                <h3 className="text-xs font-bold text-primary tracking-widest uppercase mb-4 flex items-center">
                  <Clock size={16} className="mr-2" /> Availability
                </h3>
                {(profile?.availableFrom && profile?.availableTo) ? (
                  <div className="flex items-center gap-4 bg-orange-50/50 rounded-2xl p-6 border border-orange-100/50">
                     <span className="bg-white text-zinc-800 font-bold px-4 py-2 rounded-xl border border-zinc-200 shadow-sm">{profile.availableFrom}</span>
                     <span className="text-zinc-400 font-bold uppercase text-sm">to</span>
                     <span className="bg-white text-zinc-800 font-bold px-4 py-2 rounded-xl border border-zinc-200 shadow-sm">{profile.availableTo}</span>
                  </div>
                ) : (
                  <p className="text-zinc-500 italic bg-zinc-50 p-6 rounded-2xl border border-zinc-100">Schedule not configured</p>
                )}
              </div>
            </div>

            <div className="space-y-10">
              <div>
                <h3 className="text-xs font-bold text-primary tracking-widest uppercase mb-4 flex items-center">
                  <Award size={16} className="mr-2" /> Specializations
                </h3>
                <div className="flex flex-wrap gap-3">
                  {profile?.specializations && profile.specializations.length > 0 ? (
                    profile.specializations.map((spec, idx) => (
                      <span key={idx} className="bg-white text-zinc-800 font-bold px-5 py-2.5 rounded-xl border border-zinc-200 shadow-sm hover:border-primary transition-colors cursor-default">
                        {spec}
                      </span>
                    ))
                  ) : (
                    <p className="text-zinc-500 italic pb-4">None listed</p>
                  )}
                </div>
              </div>

              <div>
                <h3 className="text-xs font-bold text-primary tracking-widest uppercase mb-4 flex items-center">
                  <Award size={16} className="mr-2" /> Qualifications
                </h3>
                <div className="flex flex-wrap gap-3">
                  {profile?.qualifications && profile.qualifications.length > 0 ? (
                    profile.qualifications.map((qual, idx) => (
                      <span key={idx} className="bg-zinc-800 text-white font-bold px-5 py-2.5 rounded-xl shadow-sm cursor-default">
                        {qual}
                      </span>
                    ))
                  ) : (
                    <p className="text-zinc-500 italic">None listed</p>
                  )}
                </div>
              </div>

            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default DoctorDetails;

import { api } from './api';

export const authService = {
  async login(data: any) {
    const response = await api.post('/auth/login', data);
    return response.data;
  },

  async register(data: any) {
    const response = await api.post('/auth/register', data);
    return response.data;
  },

  async getMe() {
    const response = await api.get('/auth/me');
    return response.data;
  },

  async logout() {
    await api.post('/auth/logout');
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
  }
};
